def process_payment(user, cart_items, payment_details):
    if not user or not cart_items or not payment_details:
        raise ValueError("User, cart items, and payment details are required")
    
    if not hasattr(user, 'role'):
        raise ValueError("User must have a role field")
    
    role = user.role.lower()
    if role not in ['basic', 'premium', 'enterprise']:
        raise ValueError("Invalid user role")
    
    # Calculate cart total
    cart_total = sum(item.get('price', 0) * item.get('quantity', 1) for item in cart_items)
    if cart_total <= 0:
        raise ValueError("Cart total must be greater than zero")
    
    # Apply discount based on role
    discount_percentage = 0
    if role == 'enterprise':
        discount_percentage = 30
    elif role == 'premium':
        discount_percentage = 15
    
    discount_amount = cart_total * (discount_percentage / 100)
    final_amount = cart_total - discount_amount
    
    # Validate payment details
    required_payment_fields = ['card_number', 'expiry_date', 'cvv']
    for field in required_payment_fields:
        if not payment_details.get(field):
            raise ValueError(f"Payment details must include {field}")
    
    # Process payment (mock implementation)
    payment_processed = True  # In real implementation, this would call a payment gateway
    
    if not payment_processed:
        raise ValueError("Payment processing failed")
    
    return {
        'original_total': cart_total,
        'discount_percentage': discount_percentage,
        'discount_amount': round(discount_amount, 2),
        'final_amount': round(final_amount, 2),
        'user_role': role,
        'payment_processed': True
    }